// Branche "recherche" : construit cfg attendu par le node d'Anthony "Resolve location & build payload"
// Le webhook recoit : { account_id, campaign_id, keywords, location, network_distance, max_results, auto_invite }

function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

const body = $input.first().json.body;

const {
  account_id,
  campaign_id,
  keywords,
  location,
  network_distance,
  max_results,
  auto_invite,
  industry,
  exclude_industry,
  exclude_titles,
} = body;

if (!account_id) throw new Error('account_id manquant dans la requete.');
if (!keywords) throw new Error('keywords manquant dans la requete.');

const distanceLabels = {
  '1': '1er degré',
  '2': '2e degré',
  '3': '3e degré et +',
};
const nd = String(network_distance || '');
const search_network_distance = nd
  ? nd.split(',').map(d => distanceLabels[d.trim()]).filter(Boolean)
  : [];

return [{
  json: {
    search_id: campaign_id || uuidv4(),
    account_id,
    auto_invite: auto_invite === true,
    unipile_base_url: 'https://api22.unipile.com:15267',
    unipile_account_id: account_id,
    search_keywords: keywords,
    search_location: location || '',
    search_network_distance,
    search_limit: Math.min(Math.max(Number(max_results) || 25, 1), 50),
    search_industry: industry || '',
    search_exclude_industry: exclude_industry || '',
    search_exclude_titles: Array.isArray(exclude_titles) ? exclude_titles : [],
  },
}];

const UNIPILE_API_KEY = '___REDACTED_UNIPILE_KEY___';

// cfg vient de Code - Compute hash (HTTP - Lire curseur est entre les deux)
const cfg = $('Code - Compute hash').item.json;

// Curseur existant pour cette recherche ([] si nouvelle, [{...}] si déjà connue)
const curseurResponse = $input.first().json;
// n8n peut retourner soit l'array soit l'item directement selon la réponse HTTP
let curseurRow = null;
if (Array.isArray(curseurResponse) && curseurResponse.length > 0) {
  curseurRow = curseurResponse[0];
} else if (curseurResponse && curseurResponse.last_cursor !== undefined) {
  curseurRow = curseurResponse;
}
const last_cursor = curseurRow?.last_cursor || null;
const exhausted = curseurRow?.exhausted || false;


const {
  unipile_base_url,
  unipile_account_id,
  search_keywords,
  search_location,
  search_network_distance,
  search_limit,
  search_industry,
  search_exclude_titles,
} = cfg;

if (!unipile_account_id) {
  throw new Error('unipile_account_id manquant.');
}

async function resolveParameter(type, label) {
  if (!label || !String(label).trim()) return null;
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: `${unipile_base_url}/api/v1/linkedin/search/parameters`,
      qs: {
        type,
        keywords: String(label).trim(),
        account_id: unipile_account_id,
        limit: 1,
      },
      headers: {
        'X-API-KEY': UNIPILE_API_KEY,
        'accept': 'application/json',
      },
      json: true,
    });
    const items = resp?.items || [];
    if (items.length > 0) {
      return { id: String(items[0].id), title: items[0].title || null };
    }
    return null;
  } catch (err) {
    console.log(`AVERTISSEMENT : resolve ${type} "${label}" a echoue : ${err.message}. Filtre ignore.`);
    return null;
  }
}

const distanceMap = {
  '1er degré': 1,
  '2e degré': 2,
  '3e degré et +': 3,
};
const network_distance = (Array.isArray(search_network_distance) ? search_network_distance : [])
  .map(label => distanceMap[label])
  .filter(n => Number.isInteger(n));

const locationResolved = await resolveParameter.call(this, 'LOCATION', search_location);
const location_ids = locationResolved ? [locationResolved.id] : [];
const location_resolved_title = locationResolved ? locationResolved.title : null;

const includeIndustry = await resolveParameter.call(this, 'INDUSTRY', search_industry);

const excludeTitles = (Array.isArray(search_exclude_titles) ? search_exclude_titles : [])
  .map(t => String(t).trim())
  .filter(t => t.length > 0);

const searchBody = {
  api: 'classic',
  category: 'people',
  keywords: search_keywords,
};
if (network_distance.length > 0) searchBody.network_distance = network_distance;
if (location_ids.length > 0) searchBody.location = location_ids;
if (includeIndustry) {
  searchBody.industry = [includeIndustry.id];
}
if (last_cursor) searchBody.cursor = last_cursor;

return [{
  json: {
    ...cfg,
    search_payload: searchBody,
    location_ids,
    location_resolved_title,
    include_industry_id: includeIndustry ? includeIndustry.id : null,
    include_industry_title: includeIndustry ? includeIndustry.title : null,
    network_distance_codes: network_distance,
    exclude_titles: excludeTitles,
    search_started_at: new Date().toISOString(),
    last_cursor,
    exhausted,
  },
}];

// Recoit la reponse de /linkedin/search (classic/people).
// Format reel : { object, items: [...], paging, cursor }.
// Champs reels par profil : id, name, headline, location, network_distance, etc.
// IMPORTANT : "industry" est toujours null sur cette API, et il n'y a aucun champ
// entreprise. On extrait l'entreprise du headline en best-effort.
// Post-filtre les titres a eviter (sur le headline) avant d'ecrire dans lk_search_results.

const response = $input.first().json;
const profiles = Array.isArray(response?.items)
  ? response.items
  : (Array.isArray(response?.data) ? response.data : []);

const ctx = $items('Resolve location & build payload1')[0].json;

// Titres a eviter (post-filtrage, car classic/people ne sait pas exclure de titre)
const excludeTitles = (Array.isArray(ctx.exclude_titles) ? ctx.exclude_titles : [])
  .map(t => String(t).trim().toLowerCase())
  .filter(t => t.length > 0);

// Extrait l'entreprise du headline en best-effort : "... chez X", "... at X", "... @ X".
// Coupe aux separateurs courants car le headline melange souvent poste, boite et specialites.
function extractCompany(headline) {
  if (!headline) return '';
  const m = String(headline).match(/\b(?:chez|at|@)\s+(.+)$/i);
  if (!m) return '';
  return m[1].split(/[,|·]| - | – /)[0].trim();
}

// Post-filtrage des titres a eviter
const filtered = profiles.filter(p => {
    if (p.network_distance === 'DISTANCE_1') return false; // jamais de 1er degre (deja connecte)

  const headline = String(p.headline || '').toLowerCase();
  if (excludeTitles.length > 0 && excludeTitles.some(t => headline.includes(t))) {
    return false;
  }
  return true;
});

const rows = filtered.map(p => {
  const fullName = (p.name || '').trim();
  const headline = p.headline || '';
  const locationLinkedin = p.location || '';

  // industry : non fourni par classic/people (toujours null cote Unipile).
  const industry = p.industry || null;
  // current_company : aucun champ dedie, on derive du headline.
  const currentCompany = extractCompany(headline) || null;

  return {
    json: {
      account_id: ctx.account_id,
      search_id: ctx.search_id,
      provider_id: p.id || '',
      full_name: fullName,
      headline,
      location: locationLinkedin,
      industry,
      current_company: currentCompany,
      status: ctx.auto_invite ? 'selected' : 'pending',
    },
  };
});

return rows;

// Hash djb2 en pur JS — pas besoin de module crypto
function hashString(str) {
  let hash = 5381;
  for (let i = 0; i < str.length; i++) {
    hash = ((hash << 5) + hash) ^ str.charCodeAt(i);
    hash = hash >>> 0; // force unsigned 32bit
  }
  return hash.toString(16).padStart(8, '0');
}

const cfg = $input.first().json;

const normalized = {
  keywords: (cfg.search_keywords || '').toLowerCase().trim(),
  location: (cfg.search_location || '').toLowerCase().trim(),
  network: [...(cfg.search_network_distance || [])].sort().join(','),
  industry: (cfg.search_industry || '').toLowerCase().trim(),
};

const raw = JSON.stringify(normalized);
const query_hash = hashString(raw);

return [{ json: { ...cfg, query_hash } }];

// ============================================================
// Build send list : pour chaque client actif dans son creneau,
// calcule le quota restant et renvoie la file a envoyer.
// ============================================================
const SUPABASE_URL = 'https://omwmbqpbwprpaqaphphg.supabase.co';
const SUPABASE_KEY = '___REDACTED_JWT___';

// n8n peut retourner les clients soit en 1 item (tableau JSON entier)
// soit en N items separes (un par client). On gere les deux cas.
const allItems = $input.all();
let clientList = [];
if (allItems.length === 1 && Array.isArray(allItems[0].json)) {
  clientList = allItems[0].json;
} else {
  clientList = allItems.map(item => item.json);
}

console.log('[Build send list] ' + clientList.length + ' client(s) recus');

const now = new Date();
const todayStart = new Date(Date.UTC(
  now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate()
)).toISOString();

const sendList = [];

for (const client of clientList) {
  const {
    account_id,
    daily_invite_limit = 25,
    active_hours_start = 9,
    active_hours_end = 19,
    active_days = [1,2,3,4,5],
    timezone = 'Europe/Paris',
  } = client;

  if (!account_id) { console.log('[Build send list] client sans account_id, skip'); continue; }

  // Verifier le creneau actif (heure + jour) dans le fuseau du client
  const nowInTz = new Date().toLocaleString('en-US', { timeZone: timezone });
  const dtInTz = new Date(nowInTz);
  const hour = dtInTz.getHours();
  const jsDay = dtInTz.getDay();
  const isoDay = jsDay === 0 ? 7 : jsDay;

  console.log('[Build send list] ' + account_id + ' : heure=' + hour + ', jourISO=' + isoDay);

  if (hour < active_hours_start || hour >= active_hours_end) {
    console.log('[Build send list] ' + account_id + ' hors creneau horaire, skip');
    continue;
  }
  if (!active_days.includes(isoDay)) {
    console.log('[Build send list] ' + account_id + ' hors jours actifs, skip');
    continue;
  }

  // Compter les invitations deja envoyees aujourd'hui
  let sentToday = 0;
  try {
    const sentResp = await this.helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/lk_search_results',
      qs: {
        account_id: 'eq.' + account_id,
        status: 'eq.invited',
        sent_at: 'gte.' + todayStart,
        select: 'id',
      },
      headers: {
        apikey: SUPABASE_KEY,
        Authorization: 'Bearer ' + SUPABASE_KEY,
      },
      json: true,
    });
    sentToday = Array.isArray(sentResp) ? sentResp.length : 0;
    console.log('[Build send list] ' + account_id + ' : ' + sentToday + ' invite(s) aujourd\'hui');
  } catch(e) {
    console.log('[Build send list] Erreur count envois ' + account_id + ': ' + e.message);
  }

  const quotaRestant = Math.max(0, daily_invite_limit - sentToday);
  console.log('[Build send list] ' + account_id + ' : quota restant = ' + quotaRestant);
  if (quotaRestant === 0) { continue; }

  // Lire la file d'attente (selected, les plus anciens en premier)
  let queue = [];
  try {
    queue = await this.helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/lk_search_results',
      qs: {
        account_id: 'eq.' + account_id,
        status: 'eq.selected',
        order: 'created_at.asc',
        limit: String(quotaRestant),
        select: 'id,provider_id,full_name,headline',
      },
      headers: {
        apikey: SUPABASE_KEY,
        Authorization: 'Bearer ' + SUPABASE_KEY,
      },
      json: true,
    });
    console.log('[Build send list] ' + account_id + ' : ' + (Array.isArray(queue) ? queue.length : 0) + ' profil(s) selected');
  } catch(e) {
    console.log('[Build send list] Erreur lecture file ' + account_id + ': ' + e.message);
  }

  for (const profile of (Array.isArray(queue) ? queue : [])) {
    sendList.push({
      json: {
        account_id,
        result_id: profile.id,
        provider_id: profile.provider_id,
        full_name: profile.full_name || null,
        headline: profile.headline || null,
      },
    });
  }
}

console.log('[Build send list] Total a envoyer : ' + sendList.length);
return sendList.length > 0 ? sendList : [{ json: { __empty: true } }];

// ============================================================
// Envoyer et traiter : pour chaque profil de la file,
// envoie l'invitation Unipile puis met a jour Supabase.
// Mode runOnceForEachItem : retourner { json: {...} } (pas de tableau).
// ============================================================
const SUPABASE_URL = 'https://omwmbqpbwprpaqaphphg.supabase.co';
const SUPABASE_KEY = '___REDACTED_JWT___';
const UNIPILE_BASE_URL = 'https://api22.unipile.com:15267';
const UNIPILE_API_KEY = '___REDACTED_UNIPILE_KEY___';

const { account_id, result_id, provider_id, full_name, headline } = $json;

// 1. Envoyer l'invitation Unipile (sans message)
let inviteResult = null;
let errorType = null;

try {
  inviteResult = await this.helpers.httpRequest({
    method: 'POST',
    url: UNIPILE_BASE_URL + '/api/v1/users/invite',
    headers: {
      'X-API-KEY': UNIPILE_API_KEY,
      'accept': 'application/json',
    },
    body: { account_id, provider_id },
    json: true,
  });
} catch (err) {
  const body = err.response?.body;
  const parsed = (typeof body === 'string') ? JSON.parse(body || '{}') : (body || {});
  errorType = parsed?.error?.type || 'unknown_error';
  console.log('Erreur Unipile ' + provider_id + ': ' + errorType);
}

const success = inviteResult?.object === 'UserInvitationSent';

const IGNOREABLE = [
  'errors/already_connected',
  'errors/already_invited_recently',
  'errors/user_unreachable',
  'errors/blocked_recipient',
  'errors/cannot_invite_attendee',
];

const newStatus = success
  ? 'invited'
  : (IGNOREABLE.includes(errorType) ? 'ignored' : 'failed');

// 2. Mettre a jour lk_search_results
const updatePayload = { status: newStatus };
if (errorType) updatePayload.error_code = errorType;
if (success) updatePayload.sent_at = new Date().toISOString();

try {
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: SUPABASE_URL + '/rest/v1/lk_search_results',
    qs: { id: 'eq.' + result_id },
    headers: {
      apikey: SUPABASE_KEY,
      Authorization: 'Bearer ' + SUPABASE_KEY,
      'Content-Type': 'application/json',
      Prefer: 'return=minimal',
    },
    body: JSON.stringify(updatePayload),
  });
} catch (e) {
  console.log('Erreur MAJ lk_search_results: ' + e.message);
}

// 3. Creer le prospect dans lk_prospects si succes
if (success) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: SUPABASE_URL + '/rest/v1/lk_prospects',
      headers: {
        apikey: SUPABASE_KEY,
        Authorization: 'Bearer ' + SUPABASE_KEY,
        'Content-Type': 'application/json',
        Prefer: 'return=minimal',
      },
      body: JSON.stringify({
        account_id: account_id,
        linkedin_id: provider_id,
        full_name: full_name || '',
        job_title: headline || '',
        status: 'invited',
      }),
    });
  } catch (e) {
    console.log('Prospect deja existant ou erreur insertion: ' + e.message);
  }
}

// runOnceForEachItem : retourner un objet simple, pas un tableau
return {
  json: {
    account_id: account_id || null,
    provider_id: provider_id || null,
    result: newStatus,
    error_type: errorType || null,
  },
};

const SUPABASE_URL = 'https://omwmbqpbwprpaqaphphg.supabase.co';
const SUPABASE_KEY = '___REDACTED_JWT___';

const allItems = $input.all();
let campaigns = [];
if (allItems.length === 1 && Array.isArray(allItems[0].json)) {
  campaigns = allItems[0].json;
} else {
  campaigns = allItems.map(i => i.json);
}

const result = [];
for (const c of campaigns) {
  if (!c.id || !c.account_id) continue;
  const target = c.target_count || 500;

  // Option A : on recompte les vraies lignes en base (source de verite),
  // au lieu de faire confiance au compteur stocke total_scraped.
  let already = 0;
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/lk_search_results',
      qs: { search_id: 'eq.' + c.id, select: 'id' },
      headers: {
        apikey: SUPABASE_KEY,
        Authorization: 'Bearer ' + SUPABASE_KEY,
        Prefer: 'count=exact',
        Range: '0-0',
        accept: 'application/json',
      },
      returnFullResponse: true,
      json: true,
    });
    const cr = resp.headers?.['content-range'] || '';
    already = Number(String(cr).split('/')[1]) || 0;
  } catch (err) {
    console.log('[Init scraping] count erreur ' + c.id + ' : ' + err.message);
    already = c.total_scraped || 0; // repli sur le compteur stocke
  }

  // Objectif deja atteint -> on saute, et on marque la campagne done.
  if (already >= target) {
    try {
      await this.helpers.httpRequest({
        method: 'PATCH',
        url: SUPABASE_URL + '/rest/v1/lk_searches',
        qs: { id: 'eq.' + c.id },
        headers: {
          apikey: SUPABASE_KEY,
          Authorization: 'Bearer ' + SUPABASE_KEY,
          'Content-Type': 'application/json',
          Prefer: 'return=minimal',
        },
        body: JSON.stringify({ status: 'done', total_scraped: already, last_run_at: new Date().toISOString() }),
      });
    } catch (err) {
      console.log('[Init scraping] MAJ done erreur ' + c.id + ' : ' + err.message);
    }
    continue;
  }

  const qp = c.query_params || {};
  const distanceLabels = { '1': '1er degré', '2': '2e degré', '3': '3e degré et +' };
  const nd = String(qp.network_distance || '');
  const search_network_distance = nd ? nd.split(',').map(d => distanceLabels[d.trim()]).filter(Boolean) : [];

  result.push({ json: {
    campaign_id: c.id,
    account_id: c.account_id,
    search_keywords: qp.keywords || '',
    search_location: qp.location || '',
    search_network_distance,
    search_industry: qp.industry || '',
    search_exclude_titles: Array.isArray(qp.exclude_titles) ? qp.exclude_titles : [],
    last_cursor: c.last_cursor || null,
    already,
    remaining: target - already,
    target_count: target,
    mode: c.mode || 'validation',
  }});
}

console.log('[Init scraping] ' + result.length + ' campagne(s) a scraper');
if (result.length === 0) return [{ json: { __empty: true } }];
return result;

const UNIPILE_API_KEY = '___REDACTED_UNIPILE_KEY___';
const UNIPILE_BASE_URL = 'https://api22.unipile.com:15267';

const cfg = $json;
const {
  campaign_id, account_id,
  search_keywords, search_location, search_network_distance,
  search_industry, search_exclude_titles,
  last_cursor, already, remaining, target_count, mode,
} = cfg;

async function resolveParam(type, label) {
  if (!label || !String(label).trim()) return null;
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: UNIPILE_BASE_URL + '/api/v1/linkedin/search/parameters',
      qs: { type, keywords: String(label).trim(), account_id, limit: 1 },
      headers: { 'X-API-KEY': UNIPILE_API_KEY, accept: 'application/json' },
      json: true,
    });
    const items = resp?.items || [];
    return items.length > 0 ? { id: String(items[0].id) } : null;
  } catch { return null; }
}

const distanceMap = { '1er degré': 1, '2e degré': 2, '3e degré et +': 3 };
const network_distance = (search_network_distance || [])
  .map(l => distanceMap[l]).filter(n => Number.isInteger(n));

const locationR = await resolveParam.call(this, 'LOCATION', search_location);
const industryR  = await resolveParam.call(this, 'INDUSTRY', search_industry);

const searchBody = { api: 'classic', category: 'people', keywords: search_keywords };
if (network_distance.length > 0) searchBody.network_distance = network_distance;
if (locationR) searchBody.location = [locationR.id];
if (industryR) searchBody.industry = [industryR.id];
if (last_cursor) searchBody.cursor = last_cursor;

// Option A : on ne demande que ce qui manque (max 50 par page).
const pageLimit = Math.min(50, Math.max(Number(remaining) || 0, 1));

let searchResp;
try {
  searchResp = await this.helpers.httpRequest({
    method: 'POST',
    url: UNIPILE_BASE_URL + '/api/v1/linkedin/search',
    qs: { account_id, limit: String(pageLimit) },
    headers: {
      'X-API-KEY': UNIPILE_API_KEY,
      accept: 'application/json',
      'content-type': 'application/json',
    },
    body: JSON.stringify(searchBody),
  });
} catch (err) {
  console.log('[Scrape] Erreur Unipile campaign ' + campaign_id + ': ' + err.message);
  return { json: { campaign_id, account_id, cursor_next: last_cursor, total_scraped_new: already, status_new: 'active', profiles: [] } };
}

const profiles_raw = Array.isArray(searchResp?.items) ? searchResp.items : [];
const cursor_next = searchResp?.cursor || null;
const exhausted = !cursor_next;

const excludeTitles = (search_exclude_titles || [])
  .map(t => String(t).trim().toLowerCase()).filter(t => t.length > 0);

function extractCompany(headline) {
  if (!headline) return null;
  const m = String(headline).match(/\b(?:chez|at|@)\s+(.+)$/i);
  if (!m) return null;
  return m[1].split(/[,|·]| - | – /)[0].trim();
}

let profiles = profiles_raw
  .filter(p => {
    if (p.network_distance === 'DISTANCE_1') return false; // jamais de 1er degre (deja connecte)
    const h = String(p.headline || '').toLowerCase();
    return excludeTitles.length === 0 || !excludeTitles.some(t => h.includes(t));
  })
  .map(p => ({
    account_id,
    search_id: campaign_id,
    provider_id: p.id || '',
    full_name: (p.name || '').trim(),
    headline: p.headline || '',
    location: p.location || '',
    industry: p.industry || null,
    current_company: extractCompany(p.headline) || null,
    status: mode === 'auto' ? 'selected' : 'pending',
  }));

// Garde-fou : ne jamais depasser l'objectif sur la derniere page,
// meme si Unipile renvoie une page pleine malgre le limit.
if (profiles.length > remaining) profiles = profiles.slice(0, remaining);

const total_new = profiles.length;
const total_scraped_new = (already || 0) + total_new;
const isDone = exhausted || total_scraped_new >= (target_count || 500);

console.log('[Scrape] Campaign ' + campaign_id + ' : ' + total_new + ' profils, cursor=' + (cursor_next || 'null') + ', done=' + isDone);

return { json: {
  campaign_id, account_id,
  cursor_next: isDone ? null : cursor_next,
  total_scraped_new,
  status_new: isDone ? 'done' : 'active',
  profiles,
} };

const SUPABASE_URL = 'https://omwmbqpbwprpaqaphphg.supabase.co';
const SUPABASE_KEY = '___REDACTED_JWT___';

const { campaign_id, cursor_next, status_new, profiles } = $json;

// 1) Insertion tolerante aux doublons : un doublon ne doit pas faire echouer tout le lot.
if (profiles && profiles.length > 0) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: SUPABASE_URL + '/rest/v1/lk_search_results',
      qs: { on_conflict: 'account_id,provider_id' },
      headers: {
        apikey: SUPABASE_KEY,
        Authorization: 'Bearer ' + SUPABASE_KEY,
        'Content-Type': 'application/json',
        Prefer: 'return=minimal,resolution=ignore-duplicates',
      },
      body: JSON.stringify(profiles),
    });
    console.log('[INSERT] ' + profiles.length + ' profils tentes (doublons ignores) campaign ' + campaign_id);
  } catch (err) {
    console.log('[INSERT] Erreur lk_search_results: ' + err.message);
  }
}

// 2) Compteur recale sur les VRAIES lignes en base (source de verite).
let realCount = 0;
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/lk_search_results',
    qs: { search_id: 'eq.' + campaign_id, select: 'id' },
    headers: {
      apikey: SUPABASE_KEY,
      Authorization: 'Bearer ' + SUPABASE_KEY,
      Prefer: 'count=exact',
      Range: '0-0',
      accept: 'application/json',
    },
    returnFullResponse: true,
    json: true,
  });
  const cr = resp.headers?.['content-range'] || '';
  realCount = Number(String(cr).split('/')[1]) || 0;
} catch (err) {
  console.log('[COUNT] Erreur recompte: ' + err.message);
}

// 3) MAJ campagne avec le compteur reel.
try {
  await this.helpers.httpRequest({
    method: 'PATCH',
    url: SUPABASE_URL + '/rest/v1/lk_searches',
    qs: { id: 'eq.' + campaign_id },
    headers: {
      apikey: SUPABASE_KEY,
      Authorization: 'Bearer ' + SUPABASE_KEY,
      'Content-Type': 'application/json',
      Prefer: 'return=minimal',
    },
    body: JSON.stringify({
      last_cursor: cursor_next || null,
      total_scraped: realCount,
      status: status_new,
      last_run_at: new Date().toISOString(),
    }),
  });
  console.log('[MAJ] Campaign ' + campaign_id + ' : ' + status_new + ', total reel=' + realCount);
} catch (err) {
  console.log('[MAJ] Erreur lk_searches: ' + err.message);
}

return { json: { campaign_id, inserted: profiles?.length || 0, status_new, total_scraped: realCount } };
